#### **阶段 5: 添加 API 路由** (1 小时)

```typescript
// 文件: src/dashboard/routes/audit.ts

import { FastifyInstance } from 'fastify';
import { AuditService } from '../services/audit.service';

export async function auditRoutes(fastify: FastifyInstance) {
  const auditService = new AuditService();

  // 获取审计日志列表
  fastify.get('/api/audit/logs', async (request, reply) => {
    const { page = '1', limit = '50', tableName, recordId, action } = request.query as any;

    const filter: any = {};
    if (tableName) filter.tableName = tableName;
    if (recordId) filter.recordId = parseInt(recordId);
    if (action) filter.action = action;

    const result = await auditService.queryLogs(filter, {
      page: parseInt(page),
      limit: parseInt(limit)
    });

    return reply.send(result);
  });

  // 获取记录变更历史
  fastify.get('/api/audit/records/:tableName/:recordId/history', async (request, reply) => {
    const { tableName, recordId } = request.params as { tableName: string; recordId: string };

    const history = await auditService.getRecordHistory(tableName, parseInt(recordId));
    return reply.send(history);
  });

  // 导出审计日志
  fastify.get('/api/audit/export', async (request, reply) => {
    const { format = 'json' } = request.query as { format?: 'json' | 'csv' };

    const data = await auditService.exportLogs({}, format);

    reply.type(format === 'json' ? 'application/json' : 'text/csv');
    reply.header('Content-Disposition', `attachment; filename="audit-logs.${format}"`);
    return reply.send(data);
  });

  // 清理旧日志
  fastify.delete('/api/audit/cleanup', async (request, reply) => {
    const { days = '90' } = request.query as { days?: string };

    const deletedCount = await auditService.cleanupOldLogs(parseInt(days));
    return reply.send({ deletedCount });
  });
}
```

