  ElNotification({
    title: '错误',
    message,
    type: 'error',
    duration
  })
}

/**
 * 警告通知
 */
export function showWarning(message: string) {
  ElNotification({
    title: '警告',
    message,
    type: 'warning',
    duration: 4000
  })
}

/**
 * 信息通知
 */
export function showInfo(message: string) {
  ElNotification({
    title: '提示',
    message,
    type: 'info',
    duration: 3000
  })
}

