// dashboard/tests/unit/utils/error-handler.test.ts
import { describe, it, expect, vi } from 'vitest'
import { handleApiError } from '@/utils/error-handler'

describe('ErrorHandler', () => {
  it('should handle 404 error correctly', () => {
    const error = {
      response: {
        status: 404,
        data: { error: { message: 'Not Found' } }
      }
    }

    const result = handleApiError(error, { 
      showNotification: false,
      logToConsole: false 
    })

    expect(result.message).toBe('请求的资源不存在')
  })

  it('should handle network error correctly', () => {
    const error = { request: {} }

    const result = handleApiError(error, {
      showNotification: false,
      logToConsole: false
    })

    expect(result.message).toBe('网络连接失败,请检查网络设置')
  })
})
